    '''
    Given list of integers, return list in strange order.
    Strange sorting, is when you start with the minimum value,
    then maximum of the remaining integers, then minimum and so on.

    Examples:
    strange_sort_list([1, 2, 3, 4]) == [1, 4, 2, 3]
    strange_sort_list([5, 5, 5, 5]) == [5, 5, 5, 5]
    strange_sort_list([]) == []
    '''

    # check for empty lists
    if len(lst) == 0:
        return lst

    # check for list of length 1
    if len(lst) == 1:
        return lst

    # check for list of length 2
    if len(lst) == 2:
        # check for equal values
        if lst[0] == lst[1]:
            return lst

        # check for unequal values
        elif lst[0] > lst[1]:
            return lst[::-1]

    # check for list of length 3
    if len(lst) == 3:
        # check for equal values
        if lst[0] == lst[1] and lst[1] == lst[2]:
            return lst

        # check for unequal values
        elif lst[0] > lst[1] and lst[1] > lst[2]:
            return lst[::-1]

        elif lst[0] > lst[1] and lst[1] == lst[2]:
            return lst

        elif lst[0] == lst[1] and lst[1] > lst[2]:
            return lst[::2]

    # check for list of length 4 or greater
    else:
        # check for equal values
        for i in range(1, len(lst), 2):
            # check for unequal values
            if lst[i - 1] > lst[i]:
                return lst[::2]

    # check for unequal values
    for i in range(1, len(lst), 2):
        # check for unequal values
        if lst[i - 1] > lst[i]:
            return lst[::2]

    return lst[::2]

