def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """

    # Code Here
    res_ = []

    for i in s:
        # check for alphabetical characters and convert the case
        # of the character
        if (i >= 'a' and i <= 'z'):
            res_.append(i.upper())
        elif (i >= 'A' and i <= 'Z'):
            res_.append(i.lower())
        else:
            res_.append(i)

    return "".join(res_)

